"""Render an eval run as docs/eval.md — the ablation table is the deliverable."""
from pathlib import Path


def _fmt(x: float) -> str:
    return f"{x:.3f}"


def write_report(run: dict, dest: Path) -> None:
    lines = [
        "# Lumina Retrieval & Generation Evaluation",
        "",
        f"*Generated by `make eval` on {run['timestamp']}Z — frozen dataset of "
        f"{run['dataset_size']} questions over the documented corpus in `eval/corpus/`. "
        "Do not edit by hand.*",
        "",
        "## Retrieval ablation",
        "",
        "Each row adds one component. Metrics are means over all answerable questions; "
        "binary relevance against hand-verified ground-truth chunk ids.",
        "",
        "| Configuration | recall@5 | recall@10 | MRR | NDCG@10 | p50 latency |",
        "|---|---|---|---|---|---|",
    ]
    for row in run["retrieval"]:
        m = row["metrics"]
        lines.append(
            f"| {row['config']} | {_fmt(m['recall@5'])} | {_fmt(m['recall@10'])} "
            f"| {_fmt(m['mrr'])} | {_fmt(m['ndcg@10'])} | {int(m['p50_latency_ms'])} ms |"
        )

    ref = run.get("refusal")
    if ref:
        lines += [
            "",
            "## Confidence-refusal calibration",
            "",
            f"Top cross-encoder score per query ({ref['n_answerable']} answerable, "
            f"{ref['n_unanswerable']} unanswerable questions), production config. "
            "The gate refuses when the top score is below the threshold "
            "(`MIN_RERANK_SCORE`).",
            "",
            "| Threshold | False-refusal rate | False-answer rate |",
            "|---|---|---|",
        ]
        for row in ref["sweep"]:
            lines.append(
                f"| {row['threshold']:.2f} | {_fmt(row['false_refusal_rate'])} "
                f"| {_fmt(row['false_answer_rate'])} |"
            )

    gen = run.get("generation")
    if gen:
        m = gen["metrics"]
        lines += [
            "",
            "## Generation quality (RAGAS-style, LLM judge)",
            "",
            f"Answers generated with the **{gen['config']}** configuration "
            f"(n={gen['n']}); graded by a Gemini judge with rubric prompts implementing "
            "the RAGAS metric definitions (see `eval/judge.py`).",
            "",
            "| Metric | Score |",
            "|---|---|",
            f"| Faithfulness | {_fmt(m.get('faithfulness', 0.0))} |",
            f"| Answer relevancy | {_fmt(m.get('answer_relevancy', 0.0))} |",
            f"| Context precision | {_fmt(m.get('context_precision', 0.0))} |",
            f"| Context recall | {_fmt(m.get('context_recall', 0.0))} |",
            "",
            "> **Caveat — self-evaluation bias**: the generator and the judge are both "
            "Gemini. Same-family judging is known to inflate scores; treat absolute "
            "values with skepticism and read the retrieval ablation deltas as the "
            "primary signal. See `MODEL_CARD.md`.",
        ]

    lines += [
        "",
        "## Method notes",
        "",
        "- Dataset: `eval/dataset.jsonl`, frozen; each item's `relevant_chunk_ids` were "
        "verified to contain the answer before freezing. Items were drafted by an LLM "
        "assistant from the actual chunk contents and checked against their source chunks.",
        "- Corpus ingested deterministically (`make ingest`): sorted file order, "
        "sha256-derived document ids, recursive chunking (800/150).",
        "- Retrieval runs call the production `RetrievalPipeline` in-process — the same "
        "code path the API serves, not a reimplementation.",
        "- Sparse `bm25` rows use true Okapi BM25 (`rank_bm25`) computed in-process; "
        "`fts` rows use Postgres `ts_rank_cd` (not BM25) fused in a single SQL statement.",
        "",
    ]
    dest.parent.mkdir(exist_ok=True)
    dest.write_text("\n".join(lines))
